type htmlExtractionOptions struct {
	Mode           string
	BaseURL        string
	LinkPrefixes   []string
	Limit          int
	ScriptSelector string // for mode: embedded-json — selector "tag" or "tag#id"
	JSONPath       string // for mode: embedded-json — dot-notation walk
}

type htmlExtractedPage struct {
	Title        string     `json:"title,omitempty"`
	Description  string     `json:"description,omitempty"`
	ImageURL     string     `json:"image_url,omitempty"`
	CanonicalURL string     `json:"canonical_url,omitempty"`
	Links        []htmlLink `json:"links,omitempty"`
}

type htmlLink struct {
	Rank  int    `json:"rank,omitempty"`
	Name  string `json:"name,omitempty"`
	Text  string `json:"text,omitempty"`
	Image string `json:"image,omitempty"`
	URL   string `json:"url,omitempty"`
	Slug  string `json:"slug,omitempty"`
}

// htmlRawTextTags lists the four HTML5 elements whose content is parsed as
// raw text (not as nested elements) per the HTML spec. Walking these as if
// they were normal element subtrees leaks raw markup -- e.g., a `<noscript>`
// fallback containing `<img src="...">` produces literal `<img>` text in the
// anchor's nodeText. This map is used to skip those subtrees during link-mode
// text extraction and image discovery.
var htmlRawTextTags = map[string]struct{}{
	"noscript": {},
	"script":   {},
	"style":    {},
	"template": {},
}

func extractHTMLResponse(raw []byte, opts htmlExtractionOptions) (json.RawMessage, error) {
	// Dispatch on Mode at the top so each branch owns its own parsing
	// path. embedded-json doesn't need DOM walking; running the page
	// parse + walkHTML + looksLikeHTMLChallenge unconditionally would
	// (a) waste work on every embedded-json call and (b) risk false
	// "challenge page" rejection on Next.js / Nuxt pages with generic
	// titles. Page and links share the page-mode parse.
	mode := strings.ToLower(strings.TrimSpace(opts.Mode))
	switch mode {
	case "embedded-json":
		return extractEmbeddedJSON(raw, opts)
	case "links", "page", "":
		return extractHTMLPageOrLinks(raw, opts)
	default:
		return nil, fmt.Errorf("unsupported html_extract mode: %q", opts.Mode)
	}
}

// extractHTMLPageOrLinks handles the page (default) and links modes.
// Both require parsing the HTML and walking the DOM; the only difference
// is what they return at the end.
func extractHTMLPageOrLinks(raw []byte, opts htmlExtractionOptions) (json.RawMessage, error) {
	doc, err := xhtml.Parse(strings.NewReader(string(raw)))
	if err != nil {
		return nil, fmt.Errorf("parsing HTML response: %w", err)
	}

	page := htmlExtractedPage{}
	walkHTML(doc, func(n *xhtml.Node) {
		if n.Type != xhtml.ElementNode {
			return
		}
		switch strings.ToLower(n.Data) {
		case "title":
			if page.Title == "" {
				page.Title = cleanHTMLText(nodeText(n))
			}
		case "meta":
			applyMeta(&page, n)
		case "link":
			if strings.EqualFold(attrValue(n, "rel"), "canonical") && page.CanonicalURL == "" {
				page.CanonicalURL = normalizeHTMLURL(attrValue(n, "href"), opts.BaseURL)
			}
		case "a":
			if link, ok := extractHTMLLink(n, opts); ok {
				page.Links = append(page.Links, link)
			}
		}
	})

	if looksLikeHTMLChallenge(page.Title, string(raw)) {
		return nil, fmt.Errorf("HTML response looks like a browser challenge page")
	}

	limit := opts.Limit
	if limit <= 0 {
		limit = 50
	}
	if len(page.Links) > limit {
		page.Links = page.Links[:limit]
	}

	switch strings.ToLower(strings.TrimSpace(opts.Mode)) {
	case "links":
		data, err := json.Marshal(page.Links)
		return json.RawMessage(data), err
	default:
		data, err := json.Marshal(page)
		return json.RawMessage(data), err
	}
}

// extractEmbeddedJSON parses HTML, finds the <script> tag matching
// opts.ScriptSelector (default "script#__NEXT_DATA__"), parses its text
// content as JSON, walks opts.JSONPath as dot-notation, and re-marshals
// the result as the response body. Used by Next.js (pages-router),
// Nuxt, and other SSR-React frameworks that embed serialized page state
// in a known script tag.
func extractEmbeddedJSON(raw []byte, opts htmlExtractionOptions) (json.RawMessage, error) {
	doc, err := xhtml.Parse(strings.NewReader(string(raw)))
	if err != nil {
		return nil, fmt.Errorf("parsing HTML for embedded-json: %w", err)
	}
	selector := strings.TrimSpace(opts.ScriptSelector)
	if selector == "" {
		selector = "script#__NEXT_DATA__"
	}
	tag, idFilter := parseSimpleSelector(selector)
	scriptText, found := findScriptByTagAndID(doc, tag, idFilter)
	if !found {
		return nil, fmt.Errorf("embedded-json: no element matching selector %q found in page", selector)
	}
	if scriptText == "" {
		return nil, fmt.Errorf("embedded-json: script element matched %q but has empty content", selector)
	}
	var parsed interface{}
	if err := json.Unmarshal([]byte(scriptText), &parsed); err != nil {
		return nil, fmt.Errorf("embedded-json: parsing JSON content of %q: %w", selector, err)
	}
	target := walkJSONDotPath(parsed, strings.TrimSpace(opts.JSONPath))
	out, err := json.Marshal(target)
	if err != nil {
		return nil, fmt.Errorf("embedded-json: marshaling target at %q: %w", opts.JSONPath, err)
	}
	return json.RawMessage(out), nil
}

// parseSimpleSelector splits a "tag" or "tag#id" selector into its
// components. Returns ("script", "__NEXT_DATA__") for the canonical
// Next.js case; ("script", "") for a tag-only selector. Anything more
// complex (CSS classes, attribute selectors) is out of scope for v1.
func parseSimpleSelector(selector string) (tag, id string) {
	if i := strings.Index(selector, "#"); i >= 0 {
		return selector[:i], selector[i+1:]
	}
	return selector, ""
}

// findScriptByTagAndID walks the parsed HTML document looking for the
// first element whose tag matches `tag` and (when `id` is non-empty)
// whose id attribute matches `id`. Returns the element's concatenated
// text content. Tags are matched case-insensitively; ids are
// case-sensitive (per HTML5 spec).
func findScriptByTagAndID(root *xhtml.Node, tag, id string) (string, bool) {
	var found *xhtml.Node
	walkHTML(root, func(n *xhtml.Node) {
		if found != nil || n.Type != xhtml.ElementNode {
			return
		}
		if !strings.EqualFold(n.Data, tag) {
			return
		}
		if id != "" && attrValue(n, "id") != id {
			return
		}
		found = n
	})
	if found == nil {
		return "", false
	}
	return nodeText(found), true
}

// walkJSONDotPath descends a parsed JSON value via dot-notation
// (e.g., "props.pageProps.recipesByTag.results"). Empty path returns
// the entire input. Missing intermediate keys yield nil rather than
// panicking — the marshaling step then emits JSON null. This matches
// the behavior the food52 retro tested against and avoids surfacing
// every typo as an error rather than empty data.
func walkJSONDotPath(v interface{}, path string) interface{} {
	if path == "" {
		return v
	}
	parts := strings.Split(path, ".")
	cur := v
	for _, p := range parts {
		m, ok := cur.(map[string]interface{})
		if !ok {
			return nil
		}
		cur = m[p]
	}
	return cur
}

func walkHTML(n *xhtml.Node, visit func(*xhtml.Node)) {
	if n == nil {
		return
	}
	visit(n)
	for child := n.FirstChild; child != nil; child = child.NextSibling {
		walkHTML(child, visit)
	}
}

func applyMeta(page *htmlExtractedPage, n *xhtml.Node) {
	name := strings.ToLower(attrValue(n, "name"))
	property := strings.ToLower(attrValue(n, "property"))
	content := cleanHTMLText(attrValue(n, "content"))
	if content == "" {
		return
	}
	switch {
	case page.Title == "" && (property == "og:title" || name == "twitter:title"):
		page.Title = content
	case page.Description == "" && (name == "description" || property == "og:description" || name == "twitter:description"):
		page.Description = content
	case page.ImageURL == "" && (property == "og:image" || name == "twitter:image"):
		page.ImageURL = content
	}
}

func extractHTMLLink(n *xhtml.Node, opts htmlExtractionOptions) (htmlLink, bool) {
	href := strings.TrimSpace(attrValue(n, "href"))
	if href == "" || strings.HasPrefix(href, "#") || strings.HasPrefix(strings.ToLower(href), "javascript:") {
		return htmlLink{}, false
	}
	normalized := normalizeHTMLURL(href, opts.BaseURL)
	if normalized == "" {
		return htmlLink{}, false
	}
	parsed, err := url.Parse(normalized)
	if err != nil {
		return htmlLink{}, false
	}
	if !htmlLinkMatchesPrefixes(parsed.Path, opts.LinkPrefixes) {
		return htmlLink{}, false
	}

	// Use the suppression-aware walker for anchor text. Sites like Allrecipes,
	// Food Network, and other Dotdash/Meredith properties wrap above-the-fold
	// images in <noscript> for non-JS users; the HTML parser preserves
	// noscript content as raw TextNode children, and a naive walk leaks
	// "<img src=...>" markup into the result. Suppressing noscript/script/
	// style/template subtrees in nodeTextSuppressing returns clean text.
	text := cleanHTMLText(nodeTextSuppressing(n))
	rank, name := splitRankedHTMLLinkText(text)
	if name == "" {
		name = text
	}
	image := normalizeHTMLURL(firstImageSrc(n, opts.BaseURL), opts.BaseURL)
	return htmlLink{
		Rank:  rank,
		Name:  name,
		Text:  text,
		Image: image,
		URL:   normalized,
		Slug:  htmlLinkSlug(parsed.Path, opts.LinkPrefixes),
	}, true
}

func normalizeHTMLURL(raw string, base string) string {
	ref, err := url.Parse(strings.TrimSpace(raw))
	if err != nil {
		return ""
	}
	if ref.IsAbs() {
		return ref.String()
	}
	baseURL, err := url.Parse(base)
	if err != nil || baseURL.Scheme == "" || baseURL.Host == "" {
		return ref.String()
	}
	return baseURL.ResolveReference(ref).String()
}

func htmlExtractionRequestURL(base string, path string, params map[string]string) string {
	baseURL, err := url.Parse(base)
	if err != nil || baseURL.Scheme == "" || baseURL.Host == "" {
		return base
	}
	ref, err := url.Parse(path)
	if err != nil {
		return base
	}
	full := baseURL.ResolveReference(ref)
	if len(params) > 0 {
		q := full.Query()
		for key, value := range params {
			if value != "" {
				q.Set(key, value)
			}
		}
		full.RawQuery = q.Encode()
	}
	return full.String()
}

func htmlLinkMatchesPrefixes(path string, prefixes []string) bool {
	if len(prefixes) == 0 {
		return true
	}
	for _, prefix := range prefixes {
		prefix = strings.TrimSpace(prefix)
		if prefix == "" {
			continue
		}
		if !strings.HasPrefix(prefix, "/") {
			prefix = "/" + prefix
		}
		if htmlPathMatchesPrefix(path, prefix) {
			return true
		}
	}
	return false
}

func htmlPathMatchesPrefix(path string, prefix string) bool {
	if prefix == "/@" {
		return strings.HasPrefix(path, prefix)
	}
	trimmed := strings.TrimRight(prefix, "/")
	return path == trimmed || strings.HasPrefix(path, trimmed+"/")
}

func htmlLinkSlug(path string, prefixes []string) string {
	for _, prefix := range prefixes {
		prefix = strings.TrimSpace(prefix)
		if prefix == "" {
			continue
		}
		if !strings.HasPrefix(prefix, "/") {
			prefix = "/" + prefix
		}
		rest := strings.Trim(strings.TrimPrefix(path, strings.TrimRight(prefix, "/")), "/")
		if rest == path || rest == "" {
			continue
		}
		parts := strings.Split(rest, "/")
		return parts[0]
	}
	parts := strings.Split(strings.Trim(path, "/"), "/")
	if len(parts) == 0 {
		return ""
	}
	return parts[len(parts)-1]
}

func attrValue(n *xhtml.Node, name string) string {
	for _, attr := range n.Attr {
		if strings.EqualFold(attr.Key, name) {
			return attr.Val
		}
	}
	return ""
}

func nodeText(n *xhtml.Node) string {
	var parts []string
	walkHTML(n, func(child *xhtml.Node) {
		if child.Type == xhtml.TextNode {
			parts = append(parts, child.Data)
		}
	})
	return strings.Join(parts, " ")
}

// nodeTextSuppressing walks n's descendants and concatenates TextNode content,
// skipping subtrees rooted at noscript/script/style/template elements. The
// HTML5 spec parses content of those four elements as raw text, so a normal
// walk leaks their literal markup (e.g., the `<img src=...>` inside a
// `<noscript>` fallback) into the output. Used by extractHTMLLink instead of
// nodeText to keep result fields clean.
func nodeTextSuppressing(n *xhtml.Node) string {
	var parts []string
	var walk func(*xhtml.Node)
	walk = func(node *xhtml.Node) {
		if node == nil {
			return
		}
		if node.Type == xhtml.ElementNode {
			if _, raw := htmlRawTextTags[strings.ToLower(node.Data)]; raw {
				return
			}
		}
		if node.Type == xhtml.TextNode {
			parts = append(parts, node.Data)
		}
		for child := node.FirstChild; child != nil; child = child.NextSibling {
			walk(child)
		}
	}
	walk(n)
	return strings.Join(parts, " ")
}

// firstImageSrc returns the URL of the first non-suppressed `<img>` inside
// the given node's subtree, normalized against base.
//
// Source priority (highest first):
//
//  1. `data-src` — modern lazy-loading attribute; carries the real URL when
//     `src` is a placeholder (1x1 pixel, base64 transparent gif). Most
//     content-heavy sites that lazy-load (Pinterest, NYT Cooking, Food52)
//     follow this pattern, so `data-src` beats `src` when both are present.
//  2. `data-srcset` / `srcset` — first comma-separated URL. Responsive image
//     hint lists; we take the first declared candidate for simplicity.
//  3. `src` — final fallback for plain `<img>` tags without lazy-loading.
//
// Suppressed subtrees (noscript/script/style/template) are skipped, so an
// `<img>` rendered for JS-disabled users does not get picked when an
// above-the-fold rendered image exists.
//
// Limitation: returns the FIRST matching image in DOM order, with no quality
// heuristic. Sites that put a small icon (badge, share button, profile pic)
// before the hero image will have the icon URL surfaced. Acceptable for
// recipe-card and product-card layouts where hero images come first;
// document the limitation if a CLI's spec target uses an icon-first layout.
//
// Returns empty string when no image is found.
func firstImageSrc(n *xhtml.Node, base string) string {
	_ = base // base is used by the caller's normalizeHTMLURL wrapper, not here
	if n == nil {
		return ""
	}
	var found string
	var walk func(*xhtml.Node)
	walk = func(node *xhtml.Node) {
		if found != "" || node == nil {
			return
		}
		if node.Type == xhtml.ElementNode {
			if _, raw := htmlRawTextTags[strings.ToLower(node.Data)]; raw {
				return
			}
			if strings.EqualFold(node.Data, "img") {
				// Priority 1: data-src (lazy-load real URL)
				if src := strings.TrimSpace(attrValue(node, "data-src")); src != "" {
					found = src
					return
				}
				// Priority 2: data-srcset / srcset (first candidate)
				if srcset := strings.TrimSpace(attrValue(node, "data-srcset")); srcset != "" {
					if src := firstSrcsetURL(srcset); src != "" {
						found = src
						return
					}
				}
				if srcset := strings.TrimSpace(attrValue(node, "srcset")); srcset != "" {
					if src := firstSrcsetURL(srcset); src != "" {
						found = src
						return
					}
				}
				// Priority 3: plain src (may be a placeholder, but the only
				// signal available for non-lazy-loaded images)
				if src := strings.TrimSpace(attrValue(node, "src")); src != "" {
					found = src
					return
				}
			}
		}
		for child := node.FirstChild; child != nil; child = child.NextSibling {
			if found != "" {
				return
			}
			walk(child)
		}
	}
	walk(n)
	return found
}

// firstSrcsetURL extracts the first URL from a srcset / data-srcset attribute.
// Srcset format is comma-separated `URL DESCRIPTOR` pairs, e.g.:
//
//	"https://x.com/a.jpg 1x, https://x.com/a@2x.jpg 2x"
//
// We take the first URL (first whitespace-separated token of the first
// comma-separated entry). Returns empty string if the value is malformed.
func firstSrcsetURL(srcset string) string {
	if srcset == "" {
		return ""
	}
	first := srcset
	if i := strings.IndexByte(first, ','); i >= 0 {
		first = first[:i]
	}
	first = strings.TrimSpace(first)
	if i := strings.IndexAny(first, " \t"); i >= 0 {
		first = first[:i]
	}
	return strings.TrimSpace(first)
}

var htmlWhitespace = regexp.MustCompile(`\s+`)
var htmlRankedText = regexp.MustCompile(`^(\d+)[.)]\s+(.+)$`)

func cleanHTMLText(value string) string {
	value = stdhtml.UnescapeString(value)
	return strings.TrimSpace(htmlWhitespace.ReplaceAllString(value, " "))
}

func splitRankedHTMLLinkText(value string) (int, string) {
	value = cleanHTMLText(value)
	matches := htmlRankedText.FindStringSubmatch(value)
	if len(matches) != 3 {
		return 0, value
	}
	rank, err := strconv.Atoi(matches[1])
	if err != nil {
		return 0, value
	}
	return rank, matches[2]
}

func looksLikeHTMLChallenge(title string, raw string) bool {
	combined := strings.ToLower(title + "\n" + raw)
	markers := []string{
		"<title>just a moment",
		"cf-browser-verification",
		"cf-challenge",
		"cf-mitigated",
		"_cf_chl_",
		"challenge-platform",
		"verify you are human",
	}
	for _, marker := range markers {
		if strings.Contains(combined, marker) {
			return true
		}
	}
	return false
}
